SELECT sr.id, sr.tenant_id, sr.leaderboard_id, sr.instance_id,
       sr.metric_id, sr.user_id, sr.score, sr.payload,
       m.name AS metric_name, m.metric_id AS metric_external_id
FROM score_record sr
JOIN metric m ON sr.metric_id = m.id
WHERE sr.leaderboard_id = #{leaderboardId}
  AND sr.instance_id = #{instanceId}
  AND sr.user_id IN

      #{uid}
